export const meta = {
  name: 'qa-restful-db-insert',
  description: 'QA: RESTful web service form data DB registration pattern',
  phases: [
    { title: 'Semantic Search', detail: 'Search knowledge files for relevant sections' },
    { title: 'Read Sections', detail: 'Read selected section content' },
    { title: 'Generate Answer', detail: 'Generate and verify Japanese answer' },
  ],
}

phase('Semantic Search')
const searchResult = await agent(
  `Execute the semantic search workflow defined in workflows/semantic-search.md.

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

Query: "フォームから受け取ったデータをDBに登録する処理の実装パターンを知りたい（処理方式: RESTfulウェブサービス）（目的: 実装したい）"

Instructions:
1. Read the file workflows/semantic-search.md to understand the workflow
2. Execute the workflow with the query above
3. For each page evaluated, record why it was selected or skipped
4. For each section evaluated, record why it was selected (high/partial) or skipped
5. Return a JSON object with:
   {
     "selected_sections": [{"file": "<path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}],
     "selected_pages": [{"path": "<path relative to knowledge/>", "reason": "<why selected>"}],
     "excluded_pages": [{"path": "<path relative to knowledge/>", "reason": "<why skipped>"}],
     "excluded_sections": [{"file": "<path>", "section_id": "<sN>", "reason": "<why skipped>"}]
   }`,
  {
    schema: {
      type: 'object',
      properties: {
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_sections', 'selected_pages', 'excluded_pages', 'excluded_sections']
    }
  }
)

phase('Read Sections')
const readResult = await agent(
  `Read section content from knowledge files.

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

Selected sections to read (max 10, prioritize high relevance):
${JSON.stringify(searchResult.selected_sections, null, 2)}

Instructions:
1. From the selected_sections, take up to 10 sections (all "high" first, then "partial")
2. Build the argument list: for each section, format as "file:section_id" 
3. Run: bash scripts/read-sections.sh <args...>
4. Return the output as sections_content, along with the list of section IDs passed to read-sections.sh`,
  {
    schema: {
      type: 'object',
      properties: {
        sections_content: { type: 'string' },
        read_sections: {
          type: 'array',
          items: { type: 'string' }
        }
      },
      required: ['sections_content', 'read_sections']
    }
  }
)

phase('Generate Answer')
const answerResult = await agent(
  `Generate and verify a Japanese answer about RESTful web service DB registration patterns.

Question: フォームから受け取ったデータをDBに登録する処理の実装パターンを知りたい（処理方式: RESTfulウェブサービス）（目的: 実装したい）

processing_type: RESTfulウェブサービス
purpose: 実装したい

sections_content:
${readResult.sections_content}

## Step 5: Generate Answer

If sections_content is empty, output "この情報は知識ファイルに含まれていません。" and stop.

Otherwise generate a Japanese answer with this format:

**結論**: Direct answer (1-2 sentences) with specific method/class names
**根拠**: Code examples, config examples, or spec info (in code blocks)
**注意点**: Constraints, common mistakes (omit if nothing applies)
参照: Only sections actually cited (file.json:sN format, omit category path)

Stay within 500 tokens (up to 800 for complex questions).
Focus on RESTful web service approaches.

## Step 6: Verify Answer

Check all Nablarch-specific claims in the answer are supported by sections_content.

Extract these claim categories:
- API names (method names, annotation names)
- Class names
- Configuration method
- Behavior spec
- Constraints
- Parameters

Do NOT extract: general Java, general programming, flow descriptions, general web concepts.

For each claim:
1. Directly stated in section → supported
2. Direct paraphrase/synonym → supported  
3. Attribute/behavior not explicitly stated → unsupported

## Step 7: Handle result

If PASS: final_answer = answer_text
If FAIL: Re-generate answer without the unsupported claims.

## Output

Return the final answer and verification details.`,
  {
    schema: {
      type: 'object',
      properties: {
        final_answer: { type: 'string' },
        verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
        issues: { type: 'array', items: { type: 'string' } },
        answer_sections_used: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        },
        answer_sections_unused: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        }
      },
      required: ['final_answer', 'verify_result', 'answer_sections_used', 'answer_sections_unused']
    }
  }
)

return {
  searchResult,
  readResult,
  answerResult
}

